29	// Username validation
30	const validateUsername = (username: string): string | null => {
31	  if (!username) return "Username is required";
32	  if (username.length < 3) return "Username must be at least 3 characters";
33	  if (username.length > 30) return "Username must be under 30 characters";
34	  if (/^[._-]/.test(username)) return "Username cannot start with a dot, underscore, or hyphen";
35	  if (/[._-]$/.test(username)) return "Username cannot end with a dot, underscore, or hyphen";
36	  if (/[._-]{2,}/.test(username)) return "Username cannot have consecutive special characters";
37	  if (!/^[a-zA-Z0-9._-]+$/.test(username)) return "Only letters, numbers, dots, underscores, and hyphens allowed";
38	  if (/^\d+$/.test(username)) return "Username cannot be only numbers";
39	  const reserved = ["admin", "support", "help", "about", "pricing", "auth", "dashboard", "api", "crevia", "kira", "settings", "profile", "signup", "login"];
40	  if (reserved.includes(username.toLowerCase())) return "This username is reserved";
41	  return null;
42	};
